def execute_in_process(book, workdir):
    """Execute notebook code cells in one shared namespace and embed outputs.

    This avoids subprocess/kernel startup variability while preserving actual
    executed cell outputs, figures, tables, streams, and error validation.
    """
    import matplotlib
    matplotlib.use("Agg", force=True)
    import matplotlib.pyplot as plt
    ns = {"__name__": "__main__"}
    old_cwd = Path.cwd()
    os.chdir(workdir)
    count = 0
    try:
        for cell in book.cells:
            if cell.cell_type != "code":
                continue
            count += 1
            outputs = []
            stdout = io.StringIO()
            stderr = io.StringIO()

            def display(*objects):
                for obj in objects:
                    data = {"text/plain": repr(obj)}
                    if hasattr(obj, "_repr_html_"):
                        try:
                            html = obj._repr_html_()
                            if html:
                                data["text/html"] = html
                        except Exception:
                            pass
                    outputs.append(nbf.v4.new_output("display_data", data=data, metadata={}))

            ns["display"] = display
            plt.close("all")
            try:
                with redirect_stdout(stdout), redirect_stderr(stderr):
                    exec(compile(cell.source, f"<notebook-cell-{count}>", "exec"), ns)
            except Exception as exc:
                if stdout.getvalue():
                    outputs.append(nbf.v4.new_output("stream", name="stdout", text=stdout.getvalue()))
                if stderr.getvalue():
                    outputs.append(nbf.v4.new_output("stream", name="stderr", text=stderr.getvalue()))
                outputs.append(nbf.v4.new_output(
                    "error",
                    ename=type(exc).__name__,
                    evalue=str(exc),
                    traceback=traceback.format_exc().splitlines(),
                ))
                cell.outputs = outputs
                cell.execution_count = count
                raise
            if stdout.getvalue():
                outputs.insert(0, nbf.v4.new_output("stream", name="stdout", text=stdout.getvalue()))
            if stderr.getvalue():
                outputs.append(nbf.v4.new_output("stream", name="stderr", text=stderr.getvalue()))
            for number in plt.get_fignums():
                fig = plt.figure(number)
                buffer = io.BytesIO()
                fig.savefig(buffer, format="png", bbox_inches="tight", dpi=110)
                encoded = base64.b64encode(buffer.getvalue()).decode("ascii")
                outputs.append(nbf.v4.new_output(
                    "display_data",
                    data={"image/png": encoded, "text/plain": "<Figure>"},
                    metadata={},
                ))
            plt.close("all")
            cell.outputs = outputs
            cell.execution_count = count
    finally:
        os.chdir(old_cwd)
    return book

